import sys
from collections import deque
from typing import List

class Node:
    def __init__(self, val: int):
        self.val = val
        self.left = None
        self.right = None

class Solution:
    def bottomView(self, root: 'Node') -> List[int]:
        if not root:
            return []
        hd_node = {}
        q = deque([(root, 0)])
        while q:
            node, hd = q.popleft()
            hd_node[hd] = node.val
            if node.left:
                q.append((node.left, hd - 1))
            if node.right:
                q.append((node.right, hd + 1))
        return [hd_node[hd] for hd in sorted(hd_node)]

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    values = [int(next(it)) for _ in range(n)]
    nodes = {i + 1: Node(values[i]) for i in range(n)}
    # remaining tokens are edges parent child
    while True:
        try:
            p = int(next(it))
            c = int(next(it))
        except StopIteration:
            break
        parent = nodes[p]
        child = nodes[c]
        if not parent.left:
            parent.left = child
        else:
            parent.right = child
    # find root (node that never appears as child)
    all_ids = set(range(1, n + 1))
    child_ids = set()
    it2 = iter(data)
    next(it2)  # skip n
    for _ in range(n):
        next(it2)
    while True:
        try:
            p = int(next(it2))
            c = int(next(it2))
            child_ids.add(c)
        except StopIteration:
            break
    root_id = (all_ids - child_ids).pop()
    root = nodes[root_id]
    sol = Solution()
    ans = sol.bottomView(root)
    print(' '.join(map(str, ans)))

