#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* left;
    Node* right;
    Node(int v) : val(v), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    vector<int> bottomView(Node* root) {
        if (!root) return {};
        unordered_map<int, int> hd_node;
        queue<pair<Node*, int>> q;
        q.push({root, 0});
        while (!q.empty()) {
            auto _tmp_binding_0 = q.front(); auto node = _tmp_binding_0.first; auto hd = _tmp_binding_0.second; q.pop();
            hd_node[hd] = node->val;
            if (node->left) q.push({node->left, hd - 1});
            if (node->right) q.push({node->right, hd + 1});
        }
        vector<int> hds;
        hds.reserve(hd_node.size());
        for (auto &p : hd_node) hds.push_back(p.first);
        sort(hds.begin(), hds.end());
        vector<int> res;
        res.reserve(hds.size());
        for (int hd : hds) res.push_back(hd_node[hd]);
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n + 1);
    for (int i = 1; i <= n; ++i) cin >> vals[i];
    unordered_map<int, Node*> nodes;
    for (int i = 1; i <= n; ++i) nodes[i] = new Node(vals[i]);
    vector<pair<int,int>> edges;
    int p, c;
    while (cin >> p >> c) {
        edges.emplace_back(p, c);
        Node* parent = nodes[p];
        Node* child = nodes[c];
        if (!parent->left) parent->left = child;
        else parent->right = child;
    }
    // find root
    unordered_set<int> childSet;
    for (auto &e : edges) childSet.insert(e.second);
    int rootId = 1;
    for (int i = 1; i <= n; ++i) if (!childSet.count(i)) { rootId = i; break; }
    Solution sol;
    vector<int> ans = sol.bottomView(nodes[rootId]);
    for (size_t i = 0; i < ans.size(); ++i) {
        if (i) cout << ' ';
        cout << ans[i];
    }
    cout << "\n";
    return 0;
}
